'use client';

import type * as React from 'react';

import {Direction} from 'radix-ui';

/**
 * Wraps your app to provide global reading direction. All primitives will adjust their behavior based on the `dir` prop.
 *
 * ### Component Props
 *
 * See [Direction Provider props](https://www.radix-ui.com/primitives/docs/utilities/direction-provider) documentation for full details.
 *
 * | Prop         | Type             | Default |
 * | :----------- | :--------------- | :------ |
 * | _dir_        | `"ltr" \| "rtl"` | -       |
 * | _direction_  | `"ltr" \| "rtl"` | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <DirectionProvider dir="rtl">
 *   <App />
 * </DirectionProvider>
 * ```
 */
function DirectionProvider({
  dir,
  direction,
  children,
}: React.ComponentProps<typeof Direction.DirectionProvider> & {
  direction?: React.ComponentProps<typeof Direction.DirectionProvider>['dir'];
}) {
  return (
    <Direction.DirectionProvider dir={direction ?? dir}>
      {children}
    </Direction.DirectionProvider>
  );
}

/**
 * A hook that returns the current reading direction (`"ltr"` or `"rtl"`) from the nearest `DirectionProvider`.
 *
 * ### Example Usage
 *
 * ```tsx
 * function MyComponent() {
 *   const direction = useDirection();
 *   return <div>{direction === "rtl" ? "Right to left" : "Left to right"}</div>;
 * }
 * ```
 */
const useDirection = Direction.useDirection;

export {DirectionProvider, useDirection};
